@app.route("/introspect", methods=["POST"])
def introspect():
    token = request.form.get("token")
    t = TOKENS.get(token)
    if not t:
        return jsonify(active=False)
    if t["expires_at"] < now():
        return jsonify(active=False)
    return jsonify(
        active=True,
        client_id=t["client_id"],
        scope=t.get("scope", ""),
        sub=t.get("sub"),
        exp=t["expires_at"],
        iat=t["issued_at"],
    )


